        public Config cloudCertPin(String pin) { this.cloudCertPin = pin; return this; }
        public Config cloudTimeoutSeconds(int seconds) { this.cloudTimeoutSeconds = seconds; return this; }
        public Config localTimeoutSeconds(int seconds) { this.localTimeoutSeconds = seconds; return this; }
        public Config localDiscoveryTimeoutSeconds(int seconds) { this.localDiscoveryTimeoutSeconds = seconds; return this; }
        public Config cacheSizeMb(int mb) { this.cacheSizeMb = mb; return this; }
        public Config enableLogging(boolean enable) { this.enableLogging = enable; return this; }
        public Config cloudRetryConfig(RetryConfig config) { this.cloudRetryConfig = config; return this; }
