    private IoTHttpClient(Context context, Config config) {
        this.context = context;
        this.cloudBaseUrl = config.cloudBaseUrl;
        this.authTokenManager = new AuthTokenManager();
        this.mainHandler = new Handler(Looper.getMainLooper());
        this.deviceRegistry = new ConcurrentHashMap<>();
        this.gson = new GsonBuilder()
                .setDateFormat("yyyy-MM-dd'T'HH:mm:ss.SSSZ")
                .create();

        // Logging interceptor
        HttpLoggingInterceptor loggingInterceptor = new HttpLoggingInterceptor(
                message -> Log.d(TAG, message)
        );
        loggingInterceptor.setLevel(config.enableLogging ?
                HttpLoggingInterceptor.Level.BODY : HttpLoggingInterceptor.Level.NONE);

        // Cloud client with full security
        OkHttpClient.Builder cloudBuilder = new OkHttpClient.Builder()
                .connectTimeout(config.cloudTimeoutSeconds, TimeUnit.SECONDS)
                .readTimeout(config.cloudTimeoutSeconds, TimeUnit.SECONDS)
                .writeTimeout(config.cloudTimeoutSeconds, TimeUnit.SECONDS)
                .connectionPool(new ConnectionPool(5, 5, TimeUnit.MINUTES))
                .addInterceptor(new AuthInterceptor(authTokenManager))
                .addInterceptor(new RetryInterceptor(config.cloudRetryConfig))
                .addInterceptor(loggingInterceptor);

        // Certificate pinning for cloud
        if (config.cloudCertPin != null && !config.cloudCertPin.isEmpty()) {
            String host = HttpUrl.parse(config.cloudBaseUrl).host();
            CertificatePinner pinner = new CertificatePinner.Builder()
                    .add(host, config.cloudCertPin)
                    .build();
            cloudBuilder.certificatePinner(pinner);
        }

        // Cache for cloud requests
        File cacheDir = new File(context.getCacheDir(), "iot_http_cache");
        Cache cache = new Cache(cacheDir, config.cacheSizeMb * 1024L * 1024L);
        cloudBuilder.cache(cache);

        this.cloudClient = cloudBuilder.build();

        // Local HTTP client (plaintext for legacy devices)
        this.localHttpClient = new OkHttpClient.Builder()
                .connectTimeout(config.localTimeoutSeconds, TimeUnit.SECONDS)
                .readTimeout(config.localTimeoutSeconds, TimeUnit.SECONDS)
                .writeTimeout(config.localTimeoutSeconds, TimeUnit.SECONDS)
                .connectionPool(new ConnectionPool(10, 2, TimeUnit.MINUTES))
                .addInterceptor(new RetryInterceptor(config.localRetryConfig))
                .addInterceptor(loggingInterceptor)
                .build();

        // Local HTTPS client (with optional trust-all for self-signed certs on devices)
        OkHttpClient.Builder localHttpsBuilder = new OkHttpClient.Builder()
                .connectTimeout(config.localTimeoutSeconds, TimeUnit.SECONDS)
                .readTimeout(config.localTimeoutSeconds, TimeUnit.SECONDS)
                .writeTimeout(config.localTimeoutSeconds, TimeUnit.SECONDS)
                .connectionPool(new ConnectionPool(10, 2, TimeUnit.MINUTES))
                .addInterceptor(new RetryInterceptor(config.localRetryConfig))
                .addInterceptor(loggingInterceptor);

        if (config.trustAllLocalCerts) {
            configureTrustAllCerts(localHttpsBuilder);
        }

        this.localHttpsClient = localHttpsBuilder.build();
    }

    /**
     * Configure client to trust all certificates (for local self-signed device certs)
     */
    private void configureTrustAllCerts(OkHttpClient.Builder builder) {
        try {
            final TrustManager[] trustAllCerts = new TrustManager[]{
                    new X509TrustManager() {
                        @Override
                        public void checkClientTrusted(X509Certificate[] chain, String authType) {}

                        @Override
                        public void checkServerTrusted(X509Certificate[] chain, String authType) {}

                        @Override
                        public X509Certificate[] getAcceptedIssuers() {
                            return new X509Certificate[]{};
                        }
                    }
            };

            SSLContext sslContext = SSLContext.getInstance("TLS");
            sslContext.init(null, trustAllCerts, new SecureRandom());
            SSLSocketFactory sslSocketFactory = sslContext.getSocketFactory();

            builder.sslSocketFactory(sslSocketFactory, (X509TrustManager) trustAllCerts[0]);
            builder.hostnameVerifier((hostname, session) ->
                    isLocalAddress(hostname)
            );
        } catch (NoSuchAlgorithmException | KeyManagementException e) {
            Log.e(TAG, "Failed to configure trust-all certs", e);
        }
    }

    private boolean isLocalAddress(String host) {
        return host.startsWith("192.168.") || host.startsWith("10.") ||
                host.startsWith("172.16.") || host.startsWith("172.17.") ||
                host.startsWith("172.18.") || host.startsWith("172.19.") ||
                host.startsWith("172.2") || host.startsWith("172.30.") ||
                host.startsWith("172.31.") ||
                host.equals("localhost") || host.equals("127.0.0.1");
    }

    /**
     * Get the appropriate OkHttpClient for the given URL
     */
    private OkHttpClient getClientForUrl(String url) {
        HttpUrl httpUrl = HttpUrl.parse(url);
        if (httpUrl == null) {
            return cloudClient;
        }

        String host = httpUrl.host();
        if (isLocalAddress(host)) {
            if (httpUrl.isHttps()) {
                return localHttpsClient;
            } else {
                return localHttpClient;
            }
        }
        return cloudClient;
    }

