    // ==================== Cloud API Methods ====================

    /**
     * Login to cloud API
     */
    public void cloudLogin(String username, String password, IoTCallback<Map> callback) {
        Map<String, String> credentials = new HashMap<>();
        credentials.put("username", username);
        credentials.put("password", password);

        String url = cloudBaseUrl + "/api/v1/auth/login";
        postAsync(url, credentials, Map.class, new IoTCallback<Map>() {
            @Override
            public void onSuccess(IoTResponse<Map> response) {
                Map body = response.getBody();
                if (body != null) {
                    String accessToken = (String) body.get("access_token");
                    String refreshToken = (String) body.get("refresh_token");
                    Number expiresIn = (Number) body.get("expires_in");
                    if (accessToken != null) {
                        authTokenManager.setTokens(accessToken, refreshToken,
                                expiresIn != null ? expiresIn.longValue() : 3600);
                    }
                }
                callback.onSuccess(response);
            }

            @Override
            public void onFailure(IoTResponse<Map> response) {
                callback.onFailure(response);
            }
        });
    }

    /**
     * Refresh auth token
     */
    public void refreshToken(IoTCallback<Map> callback) {
        String refreshToken = authTokenManager.getRefreshToken();
        if (refreshToken == null) {
            IoTResponse<Map> errorResponse = new IoTResponse.Builder<Map>()
                    .successful(false)
                    .errorMessage("No refresh token available")
                    .build();
            postToMainThread(() -> callback.onFailure(errorResponse));
            return;
        }

        Map<String, String> body = new HashMap<>();
        body.put("refresh_token", refreshToken);

        String url = cloudBaseUrl + "/api/v1/auth/refresh";
        postAsync(url, body, Map.class, new IoTCallback<Map>() {
            @Override
            public void onSuccess(IoTResponse<Map> response) {
                Map respBody = response.getBody();
                if (respBody != null) {
                    String newAccessToken = (String) respBody.get("access_token");
                    String newRefreshToken = (String) respBody.get("refresh_token");
                    Number expiresIn = (Number) respBody.get("expires_in");
                    if (newAccessToken != null) {
                        authTokenManager.setTokens(newAccessToken, newRefreshToken,
                                expiresIn != null ? expiresIn.longValue() : 3600);
                    }
                }
                callback.onSuccess(response);
            }

            @Override
            public void onFailure(IoTResponse<Map> response) {
                callback.onFailure(response);
            }
        });
    }

