    /**
     * Discover device on local network by pinging its API endpoint
     */
    public void discoverDevice(String ipAddress, int port, String protocol,
                                IoTCallback<DeviceInfo> callback) {
        String url = protocol + "://" + ipAddress + ":" + port + "/api/info";

        OkHttpClient discoveryClient = getClientForUrl(url).newBuilder()
                .connectTimeout(3, TimeUnit.SECONDS)
                .readTimeout(3, TimeUnit.SECONDS)
                .build();

        Request request = new Request.Builder()
                .url(url)
                .get()
                .build();

        long startTime = System.currentTimeMillis();

        discoveryClient.newCall(request).enqueue(new Callback() {
            @Override
            public void onResponse(Call call, Response response) throws IOException {
                long elapsed = System.currentTimeMillis() - startTime;
                try (ResponseBody body = response.body()) {
                    String rawBody = body != null ? body.string() : "";
                    if (response.isSuccessful()) {
                        DeviceInfo device = gson.fromJson(rawBody, DeviceInfo.class);
                        if (device != null) {
                            device.setIpAddress(ipAddress);
                            device.setPort(port);
                            device.setProtocol(protocol);
                            device.setLastSeen(System.currentTimeMillis());
                            deviceRegistry.put(device.getDeviceId(), device);
                        }
                        IoTResponse<DeviceInfo> iotResponse = new IoTResponse.Builder<DeviceInfo>()
                                .statusCode(response.code())
                                .body(device)
                                .rawBody(rawBody)
                                .successful(true)
                                .responseTimeMs(elapsed)
                                .build();
                        postToMainThread(() -> callback.onSuccess(iotResponse));
                    } else {
                        IoTResponse<DeviceInfo> iotResponse = new IoTResponse.Builder<DeviceInfo>()
                                .statusCode(response.code())
                                .rawBody(rawBody)
                                .successful(false)
                                .errorMessage("Device returned " + response.code())
                                .responseTimeMs(elapsed)
                                .build();
                        postToMainThread(() -> callback.onFailure(iotResponse));
                    }
                }
            }

            @Override
            public void onFailure(Call call, IOException e) {
                long elapsed = System.currentTimeMillis() - startTime;
                IoTResponse<DeviceInfo> iotResponse = new IoTResponse.Builder<DeviceInfo>()
                        .successful(false)
                        .errorMessage("Discovery failed: " + e.getMessage())
                        .exception(e)
                        .responseTimeMs(elapsed)
                        .build();
                postToMainThread(() -> callback.onFailure(iotResponse));
            }
        });
    }

    /**
     * Scan a subnet range for devices
     */
    public void scanSubnet(String subnetPrefix, int port, String protocol,
                            IoTCallback<List<DeviceInfo>> callback) {
        new Thread(() -> {
            List<DeviceInfo> discoveredDevices = new ArrayList<>();
            Object lock = new Object();
            int[] pendingCount = {254};

            for (int i = 1; i <= 254; i++) {
                String ip = subnetPrefix + "." + i;
                discoverDevice(ip, port, protocol, new IoTCallback<DeviceInfo>() {
                    @Override
                    public void onSuccess(IoTResponse<DeviceInfo> response) {
                        synchronized (lock) {
                            if (response.getBody() != null) {
                                discoveredDevices.add(response.getBody());
                            }
                            pendingCount[0]--;
                            if (pendingCount[0] == 0) {
                                IoTResponse<List<DeviceInfo>> scanResponse =
                                        new IoTResponse.Builder<List<DeviceInfo>>()
                                                .successful(true)
                                                .body(discoveredDevices)
                                                .build();
                                postToMainThread(() -> callback.onSuccess(scanResponse));
                            }
                        }
                    }

                    @Override
                    public void onFailure(IoTResponse<DeviceInfo> response) {
                        synchronized (lock) {
                            pendingCount[0]--;
                            if (pendingCount[0] == 0) {
                                IoTResponse<List<DeviceInfo>> scanResponse =
                                        new IoTResponse.Builder<List<DeviceInfo>>()
                                                .successful(true)
                                                .body(discoveredDevices)
                                                .build();
                                postToMainThread(() -> callback.onSuccess(scanResponse));
                            }
                        }
                    }
                });
            }
        }).start();
    }

