    /**
     * Upload firmware to local device
     */
    public void localUploadFirmware(String deviceId, byte[] firmwareData, String fileName,
                                     IoTCallback<Map> callback) {
        DeviceInfo device = deviceRegistry.get(deviceId);
        if (device == null) {
            IoTResponse<Map> response = new IoTResponse.Builder<Map>()
                    .successful(false)
                    .errorMessage("Device not found in registry: " + deviceId)
                    .build();
            postToMainThread(() -> callback.onFailure(response));
            return;
        }

        String url = device.getBaseUrl() + "/api/firmware/upload";

        RequestBody fileBody = RequestBody.create(firmwareData, OCTET_STREAM);
        MultipartBody multipartBody = new MultipartBody.Builder()
                .setType(MultipartBody.FORM)
                .addFormDataPart("firmware", fileName, fileBody)
                .build();

        Request request = new Request.Builder()
                .url(url)
                .post(multipartBody)
                .build();

        executeAsync(request, Map.class, callback);
    }

