    // ==================== Request Execution ====================

    /**
     * Execute request synchronously
     */
    private <T> IoTResponse<T> executeSync(Request request, Class<T> responseType) {
        OkHttpClient client = getClientForUrl(request.url().toString());
        long startTime = System.currentTimeMillis();

        try {
            Response response = client.newCall(request).execute();
            long elapsed = System.currentTimeMillis() - startTime;

            try (ResponseBody responseBody = response.body()) {
                String rawBody = responseBody != null ? responseBody.string() : "";

                Map<String, List<String>> headersMap = new HashMap<>();
                Headers headers = response.headers();
                for (String name : headers.names()) {
                    headersMap.put(name, headers.values(name));
                }

                IoTResponse.Builder<T> builder = new IoTResponse.Builder<T>()
                        .statusCode(response.code())
                        .rawBody(rawBody)
                        .headers(headersMap)
                        .successful(response.isSuccessful())
                        .responseTimeMs(elapsed);

                if (response.isSuccessful() && !rawBody.isEmpty() && responseType != null) {
                    try {
                        if (responseType == String.class) {
                            builder.body((T) rawBody);
                        } else {
                            T parsedBody = gson.fromJson(rawBody, responseType);
                            builder.body(parsedBody);
                        }
                    } catch (JsonSyntaxException e) {
                        Log.w(TAG, "Failed to parse response body", e);
                        builder.errorMessage("Failed to parse response: " + e.getMessage());
                    }
                } else if (!response.isSuccessful()) {
                    builder.errorMessage("HTTP " + response.code() + ": " + rawBody);
                }

                return builder.build();
            }
        } catch (IOException e) {
            long elapsed = System.currentTimeMillis() - startTime;
            return new IoTResponse.Builder<T>()
                    .successful(false)
                    .errorMessage("Request failed: " + e.getMessage())
                    .exception(e)
                    .responseTimeMs(elapsed)
                    .build();
        }
    }

    /**
     * Execute request asynchronously with callback on main thread
     */
    private <T> void executeAsync(Request request, Class<T> responseType, IoTCallback<T> callback) {
        OkHttpClient client = getClientForUrl(request.url().toString());
        long startTime = System.currentTimeMillis();

        client.newCall(request).enqueue(new Callback() {
            @Override
            public void onResponse(Call call, Response response) throws IOException {
                long elapsed = System.currentTimeMillis() - startTime;

                try (ResponseBody responseBody = response.body()) {
                    String rawBody = responseBody != null ? responseBody.string() : "";

                    Map<String, List<String>> headersMap = new HashMap<>();
                    Headers headers = response.headers();
                    for (String name : headers.names()) {
                        headersMap.put(name, headers.values(name));
                    }

                    IoTResponse.Builder<T> builder = new IoTResponse.Builder<T>()
                            .statusCode(response.code())
                            .rawBody(rawBody)
                            .headers(headersMap)
                            .successful(response.isSuccessful())
                            .responseTimeMs(elapsed);

                    if (response.isSuccessful() && !rawBody.isEmpty() && responseType != null) {
                        try {
                            if (responseType == String.class) {
                                builder.body((T) rawBody);
                            } else {
                                T parsedBody = gson.fromJson(rawBody, responseType);
                                builder.body(parsedBody);
                            }
                        } catch (JsonSyntaxException e) {
                            Log.w(TAG, "Failed to parse response body", e);
                            builder.errorMessage("Failed to parse response: " + e.getMessage());
                        }
                    } else if (!response.isSuccessful()) {
                        builder.errorMessage("HTTP " + response.code() + ": " + rawBody);
                    }

                    IoTResponse<T> iotResponse = builder.build();

                    if (response.isSuccessful()) {
                        postToMainThread(() -> callback.onSuccess(iotResponse));
                    } else {
                        // Handle 401 - attempt token refresh
                        if (response.code() == 401 && !isLocalAddress(request.url().host())) {
                            handleUnauthorized(request, responseType, callback, iotResponse);
                        } else {
                            postToMainThread(() -> callback.onFailure(iotResponse));
                        }
                    }
                }
            }

            @Override
            public void onFailure(Call call, IOException e) {
                long elapsed = System.currentTimeMillis() - startTime;
                Log.e(TAG, "Request failed: " + request.url(), e);

                IoTResponse<T> iotResponse = new IoTResponse.Builder<T>()
                        .successful(false)
                        .errorMessage("Request failed: " + e.getMessage())
                        .exception(e)
                        .responseTimeMs(elapsed)
                        .build();

                postToMainThread(() -> callback.onFailure(iotResponse));
            }
        });
    }

    /**
     * Handle 401 unauthorized - attempt token refresh and retry
     */
    private <T> void handleUnauthorized(Request originalRequest, Class<T> responseType,
                                         IoTCallback<T> callback, IoTResponse<T> originalResponse) {
        String refreshToken = authTokenManager.getRefreshToken();
        if (refreshToken == null) {
            postToMainThread(() -> callback.onFailure(originalResponse));
            return;
        }

        refreshToken(new IoTCallback<Map>() {
            @Override
            public void onSuccess(IoTResponse<Map> response) {
                // Retry original request with new token
                String newToken = authTokenManager.getAccessToken();
                if (newToken != null) {
                    Request retryRequest = originalRequest.newBuilder()
                            .header("Authorization", "Bearer " + newToken)
                            .build();
                    executeAsync(retryRequest, responseType, callback);
                } else {
                    postToMainThread(() -> callback.onFailure(originalResponse));
                }
            }

            @Override
            public void onFailure(IoTResponse<Map> response) {
                authTokenManager.clearTokens();
                postToMainThread(() -> callback.onFailure(originalResponse));
            }
        });
    }

    // ==================== Utility Methods ====================

    /**
     * Check if network is available
     */
    public boolean isNetworkAvailable() {
        ConnectivityManager cm = (ConnectivityManager)
                context.getSystemService(Context.CONNECTIVITY_SERVICE);
        if (cm == null) return false;

        Network activeNetwork = cm.getActiveNetwork();
        if (activeNetwork == null) return false;

        NetworkCapabilities capabilities = cm.getNetworkCapabilities(activeNetwork);
        return capabilities != null && (
                capabilities.hasTransport(NetworkCapabilities.TRANSPORT_WIFI) ||
                        capabilities.hasTransport(NetworkCapabilities.TRANSPORT_CELLULAR) ||
                        capabilities.hasTransport(NetworkCapabilities.TRANSPORT_ETHERNET));
    }

    /**
     * Check if connected to WiFi (needed for local device communication)
     */
    public boolean isWifiConnected() {
        ConnectivityManager cm = (ConnectivityManager)
                context.getSystemService(Context.CONNECTIVITY_SERVICE);
        if (cm == null) return false;

        Network activeNetwork = cm.getActiveNetwork();
        if (activeNetwork == null) return false;

        NetworkCapabilities capabilities = cm.getNetworkCapabilities(activeNetwork);
        return capabilities != null &&
                capabilities.hasTransport(NetworkCapabilities.TRANSPORT_WIFI);
    }

    /**
     * Ping a local device to check if it's reachable
     */
    public void pingDevice(String deviceId, IoTCallback<Map> callback) {
        DeviceInfo device = deviceRegistry.get(deviceId);
        if (device == null) {
            IoTResponse<Map> response = new IoTResponse.Builder<Map>()
                    .successful(false)
                    .errorMessage("Device not found: " + deviceId)
                    .build();
            postToMainThread(() -> callback.onFailure(response));
            return;
        }

        String url = device.getBaseUrl() + "/api/ping";
        getAsync(url, Map.class, callback);
    }

    /**
     * Cancel all pending requests
     */
    public void cancelAllRequests() {
        cloudClient.dispatcher().cancelAll();
        localHttpClient.dispatcher().cancelAll();
        localHttpsClient.dispatcher().cancelAll();
    }

    /**
     * Cancel requests with a specific tag
     */
    public void cancelRequestsWithTag(Object tag) {
        cancelTaggedRequests(cloudClient, tag);
        cancelTaggedRequests(localHttpClient, tag);
        cancelTaggedRequests(localHttpsClient, tag);
    }

    private void cancelTaggedRequests(OkHttpClient client, Object tag) {
        for (Call call : client.dispatcher().queuedCalls()) {
            if (tag.equals(call.request().tag())) {
                call.cancel();
            }
        }
        for (Call call : client.dispatcher().runningCalls()) {
            if (tag.equals(call.request().tag())) {
                call.cancel();
            }
        }
    }

    /**
     * Clear HTTP cache
     */
    public void clearCache() {
        try {
            Cache cache = cloudClient.cache();
            if (cache != null) {
                cache.evictAll();
            }
        } catch (IOException e) {
            Log.e(TAG, "Failed to clear cache", e);
        }
    }

    /**
     * Shutdown the client and release resources
     */
    public void shutdown() {
        cancelAllRequests();
        cloudClient.connectionPool().evictAll();
        localHttpClient.connectionPool().evictAll();
        localHttpsClient.connectionPool().evictAll();
        clearCache();
        deviceRegistry.clear();
    }

    /**
     * Post runnable to main thread
     */
    private void postToMainThread(Runnable runnable) {
        mainHandler.post(runnable);
    }

