/**
 * Example usage in an Activity or ViewModel
 */
class IoTClientUsageExample {

    public void initializeClient(Context context) {
        IoTHttpClient.Config config = new IoTHttpClient.Config()
                .cloudBaseUrl("https://api.iot-cloud.example.com")
                .cloudTimeoutSeconds(30)
                .localTimeoutSeconds(10)
                .enableLogging(true)
                .trustAllLocalCerts(true)
                .cloudRetryConfig(RetryConfig.defaultConfig())
                .localRetryConfig(RetryConfig.localDeviceConfig());

        IoTHttpClient.initialize(context, config);
    }

    public void loginAndManageDevices() {
        IoTHttpClient client = IoTHttpClient.getInstance();

        // Login to cloud
        client.cloudLogin("admin", "password123", new IoTCallback<Map>() {
            @Override
            public void onSuccess(IoTResponse<Map> response) {
                Log.d("Example", "Login successful! Token set automatically.");

                // Discover local devices
                discoverLocalDevices(client);

                // Fetch devices from cloud
                fetchCloudDevices(client);
            }

            @Override
            public void onFailure(IoTResponse<Map> response) {
                Log.e("Example", "Login failed: " + response.getErrorMessage());
            }
        });
    }

    private void discoverLocalDevices(IoTHttpClient client) {
        // Discover a specific device (HTTP - legacy device)
        client.discoverDevice("192.168.1.100", 80, "http", new IoTCallback<DeviceInfo>() {
            @Override
            public void onSuccess(IoTResponse<DeviceInfo> response) {
                DeviceInfo device = response.getBody();
                Log.d("Example", "Found device: " + device.getDeviceName() +
                        " (response time: " + response.getResponseTimeMs() + "ms)");

                // Send a command to the device
                sendCommandToDevice(client, device.getDeviceId());
            }

            @Override
            public void onFailure(IoTResponse<DeviceInfo> response) {
                Log.w("Example", "Device not found at 192.168.1.100:80");
            }
        });

        // Discover a specific device (HTTPS - modern device)
        client.discoverDevice("192.168.1.101", 443, "https", new IoTCallback<DeviceInfo>() {
            @Override
            public void onSuccess(IoTResponse<DeviceInfo> response) {
                DeviceInfo device = response.getBody();
                Log.d("Example", "Found HTTPS device: " + device.getDeviceName());
            }

            @Override
            public void onFailure(IoTResponse<DeviceInfo> response) {
                Log.w("Example", "HTTPS device not found");
            }
        });

        // Scan entire subnet
        client.scanSubnet("192.168.1", 80, "http", new IoTCallback<List<DeviceInfo>>() {
            @Override
            public void onSuccess(IoTResponse<List<DeviceInfo>> response) {
                List<DeviceInfo> devices = response.getBody();
                Log.d("Example", "Subnet scan found " + devices.size() + " devices");
                for (DeviceInfo d : devices) {
                    Log.d("Example", "  - " + d.getDeviceName() + " at " + d.getIpAddress());
                }
            }

            @Override
            public void onFailure(IoTResponse<List<DeviceInfo>> response) {
                Log.e("Example", "Subnet scan failed");
            }
        });
    }

    private void fetchCloudDevices(IoTHttpClient client) {
        client.cloudGetDevices(new IoTCallback<DeviceInfo[]>() {
            @Override
            public void onSuccess(IoTResponse<DeviceInfo[]> response) {
                DeviceInfo[] devices = response.getBody();
                if (devices != null) {
                    Log.d("Example", "Cloud has " + devices.length + " registered devices");
                }
            }

            @Override
            public void onFailure(IoTResponse<DeviceInfo[]> response) {
                Log.e("Example", "Failed to fetch cloud devices: " + response.getErrorMessage());
            }
        });
    }

    private void sendCommandToDevice(IoTHttpClient client, String deviceId) {
        DeviceCommand command = new DeviceCommand("set_temperature")
                .addParameter("value", 22.5)
                .addParameter("unit", "celsius");

        client.localSendCommand(deviceId, command, new IoTCallback<Map>() {
            @Override
            public void onSuccess(IoTResponse<Map> response) {
                Log.d("Example", "Command sent successfully: " + response.getRawBody());
            }

            @Override
            public void onFailure(IoTResponse<Map> response) {
                Log.e("Example", "Command failed: " + response.getErrorMessage());

                // Fall back to cloud relay
                client.cloudSendCommand(deviceId, command, new IoTCallback<Map>() {
                    @Override
                    public void onSuccess(IoTResponse<Map> resp) {
                        Log.d("Example", "Command sent via cloud relay");
                    }

                    @Override
                    public void onFailure(IoTResponse<Map> resp) {
                        Log.e("Example", "Cloud relay also failed");
                    }
                });
            }
        });
    }

    private void updateDeviceConfig(IoTHttpClient client, String deviceId) {
        Map<String, Object> config = new HashMap<>();
        config.put("wifi_ssid", "NewNetwork");
        config.put("reporting_interval_sec", 60);
        config.put("led_brightness", 80);

        client.localUpdateConfig(deviceId, config, new IoTCallback<Map>() {
            @Override
            public void onSuccess(IoTResponse<Map> response) {
                Log.d("Example", "Config updated");
            }

            @Override
            public void onFailure(IoTResponse<Map> response) {
                Log.e("Example", "Config update failed: " + response.getErrorMessage());
            }
        });
    }

    private void uploadFirmware(IoTHttpClient client, String deviceId, byte[] firmwareBytes) {
        client.localUploadFirmware(deviceId, firmwareBytes, "firmware_v2.0.bin",
                new IoTCallback<Map>() {
                    @Override
                    public void onSuccess(IoTResponse<Map> response) {
                        Log.d("Example", "Firmware uploaded. Rebooting device...");
                        client.localRebootDevice(deviceId, new IoTCallback<Map>() {
                            @Override
                            public void onSuccess(IoTResponse<Map> r) {
                                Log.d("Example", "Device rebooting");
                            }

                            @Override
                            public void onFailure(IoTResponse<Map> r) {
                                Log.e("Example", "Reboot command failed");
                            }
                        });
                    }

                    @Override
                    public void onFailure(IoTResponse<Map> response) {
                        Log.e("Example", "Firmware upload failed: " + response.getErrorMessage());
                    }
                });
    }
}